220	export function getAppSettingsSnapshot(): AppSettings {
221	  if (typeof window === "undefined") {
222	    return DEFAULT_APP_SETTINGS;
223	  }
224	
225	  const raw = window.localStorage.getItem(APP_SETTINGS_STORAGE_KEY);
226	  if (raw === cachedRawSettings) {
227	    return cachedSnapshot;
228	  }
229	
230	  cachedRawSettings = raw;
231	  cachedSnapshot = parsePersistedSettings(raw);
232	  return cachedSnapshot;
233	}
