131	function EventRouter() {
132	  const syncServerReadModel = useStore((store) => store.syncServerReadModel);
133	  const setProjectExpanded = useStore((store) => store.setProjectExpanded);
134	  const removeOrphanedTerminalStates = useTerminalStateStore(
135	    (store) => store.removeOrphanedTerminalStates,
136	  );
137	  const queryClient = useQueryClient();
138	  const navigate = useNavigate();
139	  const pathname = useRouterState({ select: (state) => state.location.pathname });
140	  const pathnameRef = useRef(pathname);
141	  const lastConfigIssuesSignatureRef = useRef<string | null>(null);
142	  const handledBootstrapThreadIdRef = useRef<string | null>(null);
143	
144	  pathnameRef.current = pathname;
145	
146	  useEffect(() => {
147	    const api = readNativeApi();
148	    if (!api) return;
149	    let disposed = false;
150	    let latestSequence = 0;
151	    let syncing = false;
152	    let pending = false;
153	
154	    const flushSnapshotSync = async (): Promise<void> => {
155	      const snapshot = await api.orchestration.getSnapshot();
156	      if (disposed) return;
157	      latestSequence = Math.max(latestSequence, snapshot.snapshotSequence);
158	      syncServerReadModel(snapshot);
159	      const draftThreadIds = Object.keys(
160	        useComposerDraftStore.getState().draftThreadsByThreadId,
161	      ) as ThreadId[];
162	      const activeThreadIds = collectActiveTerminalThreadIds({
163	        snapshotThreads: snapshot.threads,
164	        draftThreadIds,
165	      });
166	      removeOrphanedTerminalStates(activeThreadIds);
167	      if (pending) {
168	        pending = false;
169	        await flushSnapshotSync();
170	      }
171	    };
172	
173	    const syncSnapshot = async () => {
174	      if (syncing) {
175	        pending = true;
176	        return;
177	      }
178	      syncing = true;
179	      pending = false;
180	      try {
181	        await flushSnapshotSync();
182	      } catch {
183	        // Keep prior state and wait for next domain event to trigger a resync.
184	      }
185	      syncing = false;
186	    };
187	
188	    void syncSnapshot().catch(() => undefined);
189	
190	    const unsubDomainEvent = api.orchestration.onDomainEvent((event) => {
191	      if (event.sequence <= latestSequence) {
192	        return;
193	      }
194	      latestSequence = event.sequence;
195	      if (event.type === "thread.turn-diff-completed" || event.type === "thread.reverted") {
196	        void queryClient.invalidateQueries({ queryKey: providerQueryKeys.all });
197	      }
198	      void syncSnapshot();
199	    });
200	    const unsubTerminalEvent = api.terminal.onEvent((event) => {
201	      const hasRunningSubprocess = terminalRunningSubprocessFromEvent(event);
202	      if (hasRunningSubprocess === null) {
203	        return;
204	      }
205	      useTerminalStateStore
206	        .getState()
207	        .setTerminalActivity(
208	          ThreadId.makeUnsafe(event.threadId),
209	          event.terminalId,
210	          hasRunningSubprocess,
211	        );
212	    });
213	    const unsubWelcome = onServerWelcome((payload) => {
214	      void (async () => {
215	        await syncSnapshot();
216	        if (disposed) {
217	          return;
218	        }
219	
220	        if (!payload.bootstrapProjectId || !payload.bootstrapThreadId) {
221	          return;
222	        }
223	        setProjectExpanded(payload.bootstrapProjectId, true);
224	
225	        if (pathnameRef.current !== "/") {
226	          return;
227	        }
228	        if (handledBootstrapThreadIdRef.current === payload.bootstrapThreadId) {
229	          return;
230	        }
231	        await navigate({
232	          to: "/$threadId",
233	          params: { threadId: payload.bootstrapThreadId },
234	          replace: true,
235	        });
236	        handledBootstrapThreadIdRef.current = payload.bootstrapThreadId;
237	      })().catch(() => undefined);
238	    });
239	    const unsubServerConfigUpdated = onServerConfigUpdated((payload) => {
240	      const signature = JSON.stringify(payload.issues);
241	      if (lastConfigIssuesSignatureRef.current === signature) {
242	        return;
243	      }
244	      lastConfigIssuesSignatureRef.current = signature;
245	
246	      void queryClient.invalidateQueries({ queryKey: serverQueryKeys.config() });
247	      const issue = payload.issues.find((entry) => entry.kind.startsWith("keybindings."));
248	      if (!issue) {
249	        toastManager.add({
250	          type: "success",
251	          title: "Keybindings updated",
252	          description: "Keybindings configuration reloaded successfully.",
253	        });
254	        return;
255	      }
256	
257	      toastManager.add({
258	        type: "warning",
259	        title: "Invalid keybindings configuration",
260	        description: issue.message,
261	        actionProps: {
262	          children: "Open keybindings.json",
263	          onClick: () => {
264	            void queryClient
265	              .ensureQueryData(serverConfigQueryOptions())
266	              .then((config) =>
267	                api.shell.openInEditor(config.keybindingsConfigPath, preferredTerminalEditor()),
268	              )
269	              .catch((error) => {
270	                toastManager.add({
271	                  type: "error",
272	                  title: "Unable to open keybindings file",
273	                  description:
274	                    error instanceof Error ? error.message : "Unknown error opening file.",
275	                });
276	              });
277	          },
278	        },
279	      });
280	    });
281	    return () => {
282	      disposed = true;
283	      unsubDomainEvent();
284	      unsubTerminalEvent();
285	      unsubWelcome();
286	      unsubServerConfigUpdated();
287	    };
288	  }, [
289	    navigate,
290	    queryClient,
291	    removeOrphanedTerminalStates,
292	    setProjectExpanded,
293	    syncServerReadModel,
294	  ]);
295	
296	  return null;
297	}
