```

**Pattern D: Type Guards and Helpers (shell.ts)**
```typescript
type ExecFileSyncLike = (
  file: string,
  args: ReadonlyArray<string>,
  options: { encoding: "utf8"; timeout: number },
) => string;

export function extractPathFromShellOutput(output: string): string | null { ... }
