export interface ThemeColors {
  readonly background: string;
  readonly foreground: string;
  /** Maps to --primary and --ring (brand / accent color). */
  readonly accent: string;
  readonly sidebar: string;
  readonly editor: string;
  readonly terminal: string;
  readonly statusBar: string;
}

export interface Theme {
  readonly id: string;
  readonly name: string;
  readonly isDark: boolean;
  readonly colors: ThemeColors;
  readonly fontFamily: string;
  readonly fontSize: string;
}

const FONT_FAMILY = '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif';

const BUILT_IN_THEMES: readonly Theme[] = [
  {
    id: "t3-dark",
    name: "T3 Dark",
    isDark: true,
    colors: {
      background: "#0d0d0d",
      foreground: "#f0f0f0",
      accent: "oklch(0.588 0.217 264)",
      sidebar: "#111111",
      editor: "#0d0d0d",
      terminal: "#0d0d0d",
      statusBar: "#161616",
    },
    fontFamily: FONT_FAMILY,
    fontSize: "14px",
  },
  {
    id: "t3-light",
    name: "T3 Light",
    isDark: false,
    colors: {
      background: "#ffffff",
      foreground: "#1f1f1f",
      accent: "oklch(0.488 0.217 264)",
      sidebar: "#f5f5f5",
      editor: "#ffffff",
      terminal: "#f5f5f5",
      statusBar: "#eeeeee",
    },
    fontFamily: FONT_FAMILY,
    fontSize: "14px",
  },
  {
    id: "t3-midnight",
    name: "T3 Midnight",
    isDark: true,
    colors: {
      background: "#0a0e1a",
      foreground: "#c8d8e8",
      accent: "oklch(0.65 0.18 240)",
      sidebar: "#0d1220",
      editor: "#0a0e1a",
      terminal: "#0a0e1a",
      statusBar: "#0d1220",
    },
    fontFamily: FONT_FAMILY,
    fontSize: "14px",
  },
] as const;

export const DEFAULT_THEME_ID = "t3-dark";

/**
 * Returns the theme with the given id, or `undefined` if not found.
 */
export function getTheme(id: string): Theme | undefined {
  return BUILT_IN_THEMES.find((t) => t.id === id);
}

/**
 * Returns all available built-in themes.
 */
export function listThemes(): readonly Theme[] {
  return BUILT_IN_THEMES;
}

