import { useCallback, useSyncExternalStore } from "react";
import {
  DEFAULT_THEME_ID,
  getTheme,
  listThemes,
  type Theme,
} from "@t3tools/shared/themes";

const STORAGE_KEY = "t3code:color-theme";

let listeners: Array<() => void> = [];
let lastSnapshot: Theme | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

function getStoredId(): string {
  try {
    return localStorage.getItem(STORAGE_KEY) ?? DEFAULT_THEME_ID;
  } catch {
    return DEFAULT_THEME_ID;
  }
}

function getThemeOrDefault(id: string): Theme {
  return getTheme(id) ?? (getTheme(DEFAULT_THEME_ID) as Theme);
}

function applyColorTheme(theme: Theme, suppressTransitions = false): void {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  // Manage the dark class
  document.documentElement.classList.toggle("dark", theme.isDark);

  // Apply color palette as inline CSS custom properties so they take
  // precedence over the stylesheet rules from index.css.
  const style = document.documentElement.style;
  style.setProperty("--background", theme.colors.background);
  style.setProperty("--foreground", theme.colors.foreground);
  style.setProperty("--card", theme.colors.sidebar);
  style.setProperty("--card-foreground", theme.colors.foreground);
  style.setProperty("--popover", theme.colors.background);
  style.setProperty("--popover-foreground", theme.colors.foreground);
  style.setProperty("--primary", theme.colors.accent);
  style.setProperty("--ring", theme.colors.accent);
  // Semantic area variables (components can opt-in to these)
  style.setProperty("--sidebar-background", theme.colors.sidebar);
  style.setProperty("--editor-background", theme.colors.editor);
  style.setProperty("--terminal-background", theme.colors.terminal);
  style.setProperty("--status-bar-background", theme.colors.statusBar);
  // Typography
  style.fontSize = theme.fontSize;

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash of unstyled content
applyColorTheme(getThemeOrDefault(getStoredId()));

function getSnapshot(): Theme {
  const id = getStoredId();
  const theme = getThemeOrDefault(id);

  if (lastSnapshot && lastSnapshot.id === theme.id) {
    return lastSnapshot;
  }

  lastSnapshot = theme;
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Listen for storage changes from other tabs
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyColorTheme(getThemeOrDefault(getStoredId()), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

export function useColorTheme() {
  const theme = useSyncExternalStore(subscribe, getSnapshot);

  const setColorTheme = useCallback((id: string) => {
    try {
      localStorage.setItem(STORAGE_KEY, id);
    } catch {
      // Ignore quota / storage errors
    }
    applyColorTheme(getThemeOrDefault(id), true);
    emitChange();
  }, []);

  return { theme, setColorTheme, availableThemes: listThemes() } as const;
}

